func NewKucoinfutures(userConfig map[string]interface{}) *Kucoinfutures {
   p := NewKucoinfuturesCore()
   p.Init(userConfig)
   return &Kucoinfutures{
       KucoinfuturesCore: p,
       Core:  p,
       exchangeTyped: NewKucoinFromCore(&(p.KucoinCore)),
   }
}
func NewKucoinfuturesFromCore(core *KucoinCore) *Kucoin {
   return &Kucoin{
       KucoinCore: core,
       Core:  core,
       exchangeTyped: NewExchangeTyped(&core.Exchange),
   }
}

